// ─────────────────────────────────────────────
// NODO 2: Extraer y Validar Datos del Evento
// ─────────────────────────────────────────────
const item = $input.first().json;
const body = item.body || item;

const ip        = body.ip         || body.source_ip || null;
const username  = body.username   || body.user      || 'desconocido';
const eventType = body.event_type || 'login_attempt';
const success   = body.success === true || body.success === 'true' || body.success === 1;
const timestamp = body.timestamp  || new Date().toISOString();
const service   = body.service    || 'SSH';

if (!ip) {
  throw new Error('Campo "ip" obligatorio no encontrado en el payload.');
}

return [{
  json: { ip, username, eventType, success, timestamp, service }
}];

// ─────────────────────────────────────────────
// NODO 3: Contador de Intentos Fallidos por IP
// ─────────────────────────────────────────────
const staticData = $getWorkflowStaticData('global');
const data = $input.first().json;
const { ip, success, timestamp } = data;

if (!staticData.counters) {
  staticData.counters = {};
}

// Login EXITOSO: resetear contador
if (success) {
  const prevCount = staticData.counters[ip]?.count || 0;
  delete staticData.counters[ip];
  return [{
    json: {
      ...data,
      failedCount: 0,
      action: 'reset_on_success',
      message: `Login exitoso. Contador reseteado (había ${prevCount} intentos previos).`
    }
  }];
}

// Login FALLIDO: incrementar contador
if (!staticData.counters[ip]) {
  staticData.counters[ip] = {
    count: 0,
    firstAttempt: timestamp,
    username: data.username
  };
}

staticData.counters[ip].count++;
staticData.counters[ip].lastAttempt = timestamp;

const failedCount  = staticData.counters[ip].count;
const firstAttempt = staticData.counters[ip].firstAttempt;

return [{
  json: {
    ...data,
    failedCount,
    firstAttempt,
    severity: failedCount >= 10 ? 'ALTA' : failedCount >= 5 ? 'MEDIA' : 'NORMAL'
  }
}];

// ─────────────────────────────────────────────
// NODO 7: Simular Bloqueo de IP
// ─────────────────────────────────────────────
const staticData = $getWorkflowStaticData('global');
const data = $input.first().json;
const { ip, failedCount, service } = data;
const blockedAt = new Date().toISOString();

const blockRecord = {
  action: 'IP_BLOCKED',
  ip,
  blockedAt,
  expiresAt: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(),
  reason: `Fuerza bruta: ${failedCount} intentos fallidos en ${service}`,
  blockedBy: 'n8n-IDS-Automated',
  duration: '24 horas',
  simulated: true
};

if (!staticData.blockedIPs) staticData.blockedIPs = {};
staticData.blockedIPs[ip] = blockRecord;

console.log('[IDS] IP BLOQUEADA:', JSON.stringify(blockRecord, null, 2));

return [{
  json: { ...data, blockRecord, ipBlocked: true }
}];

// ─────────────────────────────────────────────
// NODO 8: Registrar Incidente ALTA
// ─────────────────────────────────────────────
const data = $input.first().json;
const incident = {
  id: `INC-${Date.now()}`,
  severity: 'ALTA',
  type: 'BRUTE_FORCE_ATTACK',
  status: 'CONTENIDO',
  ip: data.ip,
  username: data.username,
  service: data.service,
  failedAttempts: data.failedCount,
  firstAttempt: data.firstAttempt,
  detectedAt: new Date().toISOString(),
  actions: ['EMAIL_ALERT_SENT', 'IP_BLOCKED_24H'],
  blockRecord: data.blockRecord || null,
  notes: 'Incidente detectado y contenido automáticamente por n8n IDS.'
};
console.log('[IDS] INCIDENTE ALTA:', JSON.stringify(incident, null, 2));
return [{ json: { incident, registrationStatus: 'OK' } }];

// ─────────────────────────────────────────────
// NODO 10: Registrar Incidente MEDIA
// ─────────────────────────────────────────────
const data = $input.first().json;
const incident = {
  id: `INC-${Date.now()}`,
  severity: 'MEDIA',
  type: 'MULTIPLE_FAILED_LOGINS',
  status: 'EN_SEGUIMIENTO',
  ip: data.ip,
  username: data.username,
  service: data.service,
  failedAttempts: data.failedCount,
  firstAttempt: data.firstAttempt,
  detectedAt: new Date().toISOString(),
  actions: ['EMAIL_ALERT_SENT', 'MONITORING_ACTIVE'],
  notes: 'IP en seguimiento. Se bloqueará automáticamente al alcanzar 10 intentos fallidos.'
};
console.log('[IDS] INCIDENTE MEDIA:', JSON.stringify(incident, null, 2));
return [{ json: { incident, registrationStatus: 'OK' } }];

// ─────────────────────────────────────────────
// NODO 11: Registrar Evento Normal
// ─────────────────────────────────────────────
const data = $input.first().json;
const logEntry = {
  type: 'INFO',
  timestamp: new Date().toISOString(),
  ip: data.ip,
  username: data.username,
  service: data.service,
  failedCount: data.failedCount || 0,
  success: data.success,
  message: data.success
    ? `Login exitoso. Contador reseteado para ${data.ip}.`
    : `Intento fallido ${data.failedCount || 1} de 5 para ${data.ip}. Sin umbral alcanzado.`
};
console.log('[IDS] EVENTO NORMAL:', JSON.stringify(logEntry));
return [{ json: { logEntry, status: 'normal', registered: true } }];
